import{_ as a,c as o,o as t,a1 as s}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Emparelhamento de DM e Controle de Acesso: Proteja seu Assistente de IA | Tutorial Clawdbot","description":"Entenda o mecanismo de proteção de emparelhamento de DM do Clawdbot, aprenda a aprovar solicitações de emparelhamento de remetentes desconhecidos via CLI, listar solicitações pendentes e gerenciar a lista de permissão. Este tutorial apresenta o processo de emparelhamento, uso de comandos CLI, configuração de políticas de acesso e práticas de segurança, incluindo solução de problemas e comando doctor.","frontmatter":{"title":"Emparelhamento de DM e Controle de Acesso: Proteja seu Assistente de IA | Tutorial Clawdbot","sidebarTitle":"Gerenciar Acesso de Estranhos","subtitle":"Emparelhamento de DM e Controle de Acesso: Proteja seu Assistente de IA","description":"Entenda o mecanismo de proteção de emparelhamento de DM do Clawdbot, aprenda a aprovar solicitações de emparelhamento de remetentes desconhecidos via CLI, listar solicitações pendentes e gerenciar a lista de permissão. Este tutorial apresenta o processo de emparelhamento, uso de comandos CLI, configuração de políticas de acesso e práticas de segurança, incluindo solução de problemas e comando doctor.","tags":["Introdução","Segurança","Emparelhamento","Controle de Acesso"],"prerequisite":["start-gateway-startup"],"order":50},"headers":[],"relativePath":"pt/moltbot/moltbot/start/pairing-approval/index.md","filePath":"pt/moltbot/moltbot/start/pairing-approval/index.md"}'),i={name:"pt/moltbot/moltbot/start/pairing-approval/index.md"};function r(n,e,l,d,p,c){return t(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="emparelhamento-de-dm-e-controle-de-acesso-proteja-seu-assistente-de-ia" tabindex="-1">Emparelhamento de DM e Controle de Acesso: Proteja seu Assistente de IA <a class="header-anchor" href="#emparelhamento-de-dm-e-controle-de-acesso-proteja-seu-assistente-de-ia" aria-label="Permalink to &quot;Emparelhamento de DM e Controle de Acesso: Proteja seu Assistente de IA&quot;">​</a></h1><h2 id="o-que-voce-vai-aprender" tabindex="-1">O Que Você Vai Aprender <a class="header-anchor" href="#o-que-voce-vai-aprender" aria-label="Permalink to &quot;O Que Você Vai Aprender&quot;">​</a></h2><p>Ao completar este tutorial, você será capaz de:</p><ul><li>✅ Entender o mecanismo padrão de proteção de emparelhamento de DM</li><li>✅ Aprovar solicitações de emparelhamento de remetentes desconhecidos</li><li>✅ Listar e gerenciar solicitações de emparelhamento pendentes</li><li>✅ Configurar diferentes políticas de acesso de DM (pairing/allowlist/open)</li><li>✅ Executar verificações doctor na configuração de segurança</li></ul><h2 id="seu-problema-atual" tabindex="-1">Seu Problema Atual <a class="header-anchor" href="#seu-problema-atual" aria-label="Permalink to &quot;Seu Problema Atual&quot;">​</a></h2><p>Você pode ter configurado o WhatsApp ou Telegram e quer conversar com seu assistente de IA, mas encontrou os seguintes problemas:</p><ul><li>&quot;Por que o Clawdbot não responde a estranhos que me enviam mensagens?&quot;</li><li>&quot;Recebi um código de emparelhamento e não sei o que significa&quot;</li><li>&quot;Quero aprovar a solicitação de alguém, mas não sei qual comando usar&quot;</li><li>&quot;Como verificar quem está aguardando aprovação?&quot;</li></ul><p>A boa notícia é: <strong>o Clawdbot habilita proteção de emparelhamento de DM por padrão</strong>, isso garante que apenas remetentes que você autorizou possam conversar com seu assistente de IA.</p><h2 id="quando-usar-esta-abordagem" tabindex="-1">Quando Usar Esta Abordagem <a class="header-anchor" href="#quando-usar-esta-abordagem" aria-label="Permalink to &quot;Quando Usar Esta Abordagem&quot;">​</a></h2><p>Quando você precisa:</p><ul><li>🛡 <strong>Proteger privacidade</strong>: Garantir que apenas pessoas confiáveis possam conversar com seu assistente de IA</li><li>✅ <strong>Aprovar estranhos</strong>: Permitir que novos remetentes acessem seu assistente de IA</li><li>🔒 <strong>Controle de acesso estrito</strong>: Limitar permissões de acesso para usuários específicos</li><li>📋 <strong>Gerenciamento em lote</strong>: Visualizar e gerenciar todas as solicitações de emparelhamento pendentes</li></ul><hr><h2 id="ideia-central" tabindex="-1">Ideia Central <a class="header-anchor" href="#ideia-central" aria-label="Permalink to &quot;Ideia Central&quot;">​</a></h2><h3 id="o-que-e-emparelhamento-de-dm" tabindex="-1">O Que É Emparelhamento de DM? <a class="header-anchor" href="#o-que-e-emparelhamento-de-dm" aria-label="Permalink to &quot;O Que É Emparelhamento de DM?&quot;">​</a></h3><p>O Clawdbot se conecta a plataformas de mensagens reais (WhatsApp, Telegram, Slack, etc.), e <strong>mensagens privadas (DM) nessas plataformas são consideradas entrada não confiável por padrão</strong>.</p><p>Para proteger seu assistente de IA, o Clawdbot fornece um <strong>mecanismo de emparelhamento</strong>:</p><div class="info custom-block"><p class="custom-block-title">Processo de Emparelhamento</p><ol><li>Um remetente desconhecido envia uma mensagem para você</li><li>O Clawdbot detecta que o remetente não está autorizado</li><li>O Clawdbot retorna um <strong>código de emparelhamento</strong> (8 caracteres)</li><li>O remetente precisa fornecer o código de emparelhamento para você</li><li>Você aprova o código via CLI</li><li>O ID do remetente é adicionado à lista de permissão</li><li>O remetente pode conversar normalmente com o assistente de IA</li></ol></div><h3 id="politica-de-dm-padrao" tabindex="-1">Política de DM Padrão <a class="header-anchor" href="#politica-de-dm-padrao" aria-label="Permalink to &quot;Política de DM Padrão&quot;">​</a></h3><p><strong>Todos os canais usam <code>dmPolicy=&quot;pairing&quot;</code> por padrão</strong>, o que significa:</p><table tabindex="0"><thead><tr><th>Política</th><th>Comportamento</th></tr></thead><tbody><tr><td><code>pairing</code></td><td>Remetentes desconhecidos recebem código de emparelhamento, mensagens não são processadas (padrão)</td></tr><tr><td><code>allowlist</code></td><td>Apenas permite remetentes da lista <code>allowFrom</code></td></tr><tr><td><code>open</code></td><td>Permite todos os remetentes (requer configuração explícita <code>&quot;*&quot;</code>)</td></tr><tr><td><code>disabled</code></td><td>Desabilita completamente a funcionalidade DM</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Lembrete de Segurança</p><p>O modo <code>pairing</code> padrão é a opção mais segura. A menos que você tenha necessidades especiais, não altere para o modo <code>open</code>.</p></div><hr><h2 id="🎒-preparativos" tabindex="-1">🎒 Preparativos <a class="header-anchor" href="#🎒-preparativos" aria-label="Permalink to &quot;🎒 Preparativos&quot;">​</a></h2><p>Certifique-se de que você:</p><ul><li>[x] Completou o tutorial <a href="./../getting-started/">Início Rápido</a></li><li>[x] Completou o tutorial <a href="./../gateway-startup/">Iniciando o Gateway</a></li><li>[x] Configurou pelo menos um canal de mensagens (WhatsApp, Telegram, Slack, etc.)</li><li>[x] O Gateway está em execução</li></ul><hr><h2 id="siga-me" tabindex="-1">Siga-me <a class="header-anchor" href="#siga-me" aria-label="Permalink to &quot;Siga-me&quot;">​</a></h2><h3 id="passo-1-entender-a-origem-do-codigo-de-emparelhamento" tabindex="-1">Passo 1: Entender a Origem do Código de Emparelhamento <a class="header-anchor" href="#passo-1-entender-a-origem-do-codigo-de-emparelhamento" aria-label="Permalink to &quot;Passo 1: Entender a Origem do Código de Emparelhamento&quot;">​</a></h3><p>Quando um remetente desconhecido envia uma mensagem para seu Clawdbot, eles recebem uma resposta semelhante a esta:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Clawdbot: access not configured.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Telegram ID: 123456789</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Pairing code: AB3D7X9K</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ask the bot owner to approve with:</span></span>
<span class="line"><span>clawdbot pairing approve telegram &lt;code&gt;</span></span></code></pre></div><p><strong>Características-chave do Código de Emparelhamento</strong> (fonte: <code>src/pairing/pairing-store.ts</code>):</p><ul><li><strong>8 caracteres</strong>: Fácil de digitar e lembrar</li><li><strong>Letras maiúsculas e números</strong>: Evita confusão</li><li><strong>Exclui caracteres confusos</strong>: Não contém 0, O, 1, I</li><li><strong>Validade de 1 hora</strong>: Expira automaticamente após esse tempo</li><li><strong>Máximo de 3 solicitações pendentes</strong>: Limpa automaticamente a solicitação mais antiga quando excedido</li></ul><h3 id="passo-2-listar-solicitacoes-de-emparelhamento-pendentes" tabindex="-1">Passo 2: Listar Solicitações de Emparelhamento Pendentes <a class="header-anchor" href="#passo-2-listar-solicitacoes-de-emparelhamento-pendentes" aria-label="Permalink to &quot;Passo 2: Listar Solicitações de Emparelhamento Pendentes&quot;">​</a></h3><p>Execute o seguinte comando no terminal:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span></span></code></pre></div><p><strong>Você deve ver</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pairing requests (1)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌──────────────────┬────────────────┬────────┬──────────────────────┐</span></span>
<span class="line"><span>│ Code            │ ID            │ Meta   │ Requested            │</span></span>
<span class="line"><span>├──────────────────┼────────────────┼────────┼──────────────────────┤</span></span>
<span class="line"><span>│ AB3D7X9K        │ 123456789      │        │ 2026-01-27T10:30:00Z │</span></span>
<span class="line"><span>└──────────────────┴────────────────┴────────┴──────────────────────┘</span></span></code></pre></div><p>Se não houver solicitações pendentes, você verá:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No pending telegram pairing requests.</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Canais Suportados</p><p>A funcionalidade de emparelhamento suporta os seguintes canais:</p><ul><li>telegram</li><li>whatsapp</li><li>slack</li><li>discord</li><li>signal</li><li>imessage</li><li>msteams</li><li>googlechat</li><li>bluebubbles</li></ul></div><h3 id="passo-3-aprovar-solicitacao-de-emparelhamento" tabindex="-1">Passo 3: Aprovar Solicitação de Emparelhamento <a class="header-anchor" href="#passo-3-aprovar-solicitacao-de-emparelhamento" aria-label="Permalink to &quot;Passo 3: Aprovar Solicitação de Emparelhamento&quot;">​</a></h3><p>Use o código de emparelhamento fornecido pelo remetente para aprovar o acesso:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AB3D7X9K</span></span></code></pre></div><p><strong>Você deve ver</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Approved telegram sender 123456789</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Efeito após Aprovação</p><p>Após a aprovação, o ID do remetente (123456789) é adicionado automaticamente à lista de permissão desse canal, armazenado em: <code>~/.clawdbot/credentials/telegram-allowFrom.json</code></p></div><h3 id="passo-4-notificar-o-remetente-opcional" tabindex="-1">Passo 4: Notificar o Remetente (Opcional) <a class="header-anchor" href="#passo-4-notificar-o-remetente-opcional" aria-label="Permalink to &quot;Passo 4: Notificar o Remetente (Opcional)&quot;">​</a></h3><p>Se você quiser notificar automaticamente o remetente, use a flag <code>--notify</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AB3D7X9K</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --notify</span></span></code></pre></div><p>O remetente receberá a seguinte mensagem (fonte: <code>src/channels/plugins/pairing-message.ts</code>):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Clawdbot access approved. Send a message to start chatting.</span></span></code></pre></div><p><strong>Nota</strong>: A flag <code>--notify</code> exige que o Clawdbot Gateway esteja em execução e que o canal esteja ativo.</p><h3 id="passo-5-verificar-que-o-remetente-pode-conversar-normalmente" tabindex="-1">Passo 5: Verificar que o Remetente Pode Conversar Normalmente <a class="header-anchor" href="#passo-5-verificar-que-o-remetente-pode-conversar-normalmente" aria-label="Permalink to &quot;Passo 5: Verificar que o Remetente Pode Conversar Normalmente&quot;">​</a></h3><p>Peça ao remetente para enviar outra mensagem, o assistente de IA deve responder normalmente.</p><hr><h2 id="ponto-de-verificacao-✅" tabindex="-1">Ponto de Verificação ✅ <a class="header-anchor" href="#ponto-de-verificacao-✅" aria-label="Permalink to &quot;Ponto de Verificação ✅&quot;">​</a></h2><p>Complete as seguintes verificações para confirmar que a configuração está correta:</p><ul><li>[ ] Executar <code>clawdbot pairing list &lt;channel&gt;</code> pode mostrar solicitações pendentes</li><li>[ ] Usar <code>clawdbot pairing approve &lt;channel&gt; &lt;code&gt;</code> pode aprovar com sucesso</li><li>[ ] O remetente aprovado pode conversar normalmente com o assistente de IA</li><li>[ ] O código de emparelhamento expira automaticamente após 1 hora (pode verificar enviando outra mensagem)</li></ul><hr><h2 id="armadilhas-comuns" tabindex="-1">Armadilhas Comuns <a class="header-anchor" href="#armadilhas-comuns" aria-label="Permalink to &quot;Armadilhas Comuns&quot;">​</a></h2><h3 id="erro-1-codigo-de-emparelhamento-nao-encontrado" tabindex="-1">Erro 1: Código de Emparelhamento Não Encontrado <a class="header-anchor" href="#erro-1-codigo-de-emparelhamento-nao-encontrado" aria-label="Permalink to &quot;Erro 1: Código de Emparelhamento Não Encontrado&quot;">​</a></h3><p><strong>Mensagem de erro</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No pending pairing request found for code: AB3D7X9K</span></span></code></pre></div><p><strong>Causas possíveis</strong>:</p><ul><li>O código de emparelhamento expirou (mais de 1 hora)</li><li>O código de emparelhamento foi inserido incorretamente (verifique maiúsculas/minúsculas)</li><li>O remetente não enviou uma mensagem real (o código de emparelhamento só é gerado quando uma mensagem é recebida)</li></ul><p><strong>Solução</strong>:</p><ul><li>Peça ao remetente para enviar outra mensagem para gerar um novo código de emparelhamento</li><li>Certifique-se de que o código de emparelhamento foi copiado corretamente (observe maiúsculas/minúsculas)</li></ul><h3 id="erro-2-canal-nao-suporta-emparelhamento" tabindex="-1">Erro 2: Canal Não Suporta Emparelhamento <a class="header-anchor" href="#erro-2-canal-nao-suporta-emparelhamento" aria-label="Permalink to &quot;Erro 2: Canal Não Suporta Emparelhamento&quot;">​</a></h3><p><strong>Mensagem de erro</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Channel xxx does not support pairing</span></span></code></pre></div><p><strong>Causas possíveis</strong>:</p><ul><li>Erro de ortografia do nome do canal</li><li>O canal não suporta funcionalidade de emparelhamento</li></ul><p><strong>Solução</strong>:</p><ul><li>Execute <code>clawdbot pairing list</code> para ver a lista de canais suportados</li><li>Use o nome correto do canal</li></ul><h3 id="erro-3-falha-na-notificacao" tabindex="-1">Erro 3: Falha na Notificação <a class="header-anchor" href="#erro-3-falha-na-notificacao" aria-label="Permalink to &quot;Erro 3: Falha na Notificação&quot;">​</a></h3><p><strong>Mensagem de erro</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Failed to notify requester: &lt;error details&gt;</span></span></code></pre></div><p><strong>Causas possíveis</strong>:</p><ul><li>Gateway não está em execução</li><li>Conexão do canal foi perdida</li><li>Problema de rede</li></ul><p><strong>Solução</strong>:</p><ul><li>Confirme que o Gateway está em execução</li><li>Verifique o status da conexão do canal: <code>clawdbot channels status</code></li><li>Não use a flag <code>--notify</code>, notifique o remetente manualmente</li></ul><hr><h2 id="resumo" tabindex="-1">Resumo <a class="header-anchor" href="#resumo" aria-label="Permalink to &quot;Resumo&quot;">​</a></h2><p>Este tutorial apresentou o mecanismo de proteção de emparelhamento de DM do Clawdbot:</p><ul><li><strong>Segurança padrão</strong>: Todos os canais usam o modo <code>pairing</code> por padrão, protegendo seu assistente de IA</li><li><strong>Processo de emparelhamento</strong>: Remetentes desconhecidos recebem um código de emparelhamento de 8 caracteres, você precisa aprovar via CLI</li><li><strong>Comandos de gerenciamento</strong>: <ul><li><code>clawdbot pairing list &lt;channel&gt;</code>: Listar solicitações pendentes</li><li><code>clawdbot pairing approve &lt;channel&gt; &lt;code&gt;</code>: Aprovar emparelhamento</li></ul></li><li><strong>Local de armazenamento</strong>: A lista de permissão é armazenada em <code>~/.clawdbot/credentials/&lt;channel&gt;-allowFrom.json</code></li><li><strong>Expiração automática</strong>: Solicitações de emparelhamento expiram automaticamente após 1 hora</li></ul><p>Lembre-se: <strong>o mecanismo de emparelhamento é a base de segurança do Clawdbot</strong>, garantindo que apenas pessoas autorizadas por você possam conversar com o assistente de IA.</p><hr><h2 id="proximo" tabindex="-1">Próximo <a class="header-anchor" href="#proximo" aria-label="Permalink to &quot;Próximo&quot;">​</a></h2><blockquote><p>Na próxima lição, aprenderemos <strong><a href="./../../faq/troubleshooting/">Solução de Problemas: Resolvendo Problemas Comuns</a></strong>.</p><p>Você vai aprender:</p><ul><li>Diagnóstico rápido e verificação de status do sistema</li><li>Resolver problemas de inicialização do Gateway, conexão de canais, erros de autenticação, etc.</li><li>Métodos de solução de problemas para falhas de chamadas de ferramentas e otimização de desempenho</li></ul></blockquote><hr><h2 id="apendice-referencia-do-codigo-fonte" tabindex="-1">Apêndice: Referência do Código-fonte <a class="header-anchor" href="#apendice-referencia-do-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência do Código-fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver localizações do código-fonte</strong></summary><blockquote><p>Última atualização: 2026-01-27</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do Arquivo</th><th>Linhas</th></tr></thead><tbody><tr><td>Geração de código de emparelhamento (8 caracteres, exclui caracteres confusos)</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L173-L181" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>173-181</td></tr><tr><td>Armazenamento e TTL de solicitações de emparelhamento (1 hora)</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L11-L14" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>11-14</td></tr><tr><td>Comando de aprovação de emparelhamento</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/cli/pairing-cli.ts#L107-L143" target="_blank" rel="noreferrer"><code>src/cli/pairing-cli.ts</code></a></td><td>107-143</td></tr><tr><td>Geração de mensagem de código de emparelhamento</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-messages.ts#L4-L20" target="_blank" rel="noreferrer"><code>src/pairing/pairing-messages.ts</code></a></td><td>4-20</td></tr><tr><td>Armazenamento da lista de permissão</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L457-L461" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>457-461</td></tr><tr><td>Lista de canais que suportam <code>pairing</code></td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/channels/plugins/pairing.ts#L11-L16" target="_blank" rel="noreferrer"><code>src/channels/plugins/pairing.ts</code></a></td><td>11-16</td></tr><tr><td>Política de DM padrão (pairing)</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/config/zod-schema.providers-core.ts#L93" target="_blank" rel="noreferrer"><code>src/config/zod-schema.providers-core.ts</code></a></td><td>93</td></tr></tbody></table><p><strong>Constantes-chave</strong>:</p><ul><li><code>PAIRING_CODE_LENGTH = 8</code>: Comprimento do código de emparelhamento</li><li><code>PAIRING_CODE_ALPHABET = &quot;ABCDEFGHJKLMNPQRSTUVWXYZ23456789&quot;</code>: Conjunto de caracteres do código de emparelhamento (exclui 0O1I)</li><li><code>PAIRING_PENDING_TTL_MS = 60 * 60 * 1000</code>: Validade da solicitação de emparelhamento (1 hora)</li><li><code>PAIRING_PENDING_MAX = 3</code>: Número máximo de solicitações pendentes</li></ul><p><strong>Funções-chave</strong>:</p><ul><li><code>approveChannelPairingCode()</code>: Aprovar código de emparelhamento e adicionar à lista de permissão</li><li><code>listChannelPairingRequests()</code>: Listar solicitações de emparelhamento pendentes</li><li><code>upsertChannelPairingRequest()</code>: Criar ou atualizar solicitação de emparelhamento</li><li><code>addChannelAllowFromStoreEntry()</code>: Adicionar remetente à lista de permissão</li></ul></details>`,92)])])}const u=a(i,[["render",r]]);export{h as __pageData,u as default};
